module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output reg valid_out,
    output dout
); 
    reg [2:0] cnt;
    reg [3:0] data;
    always @(posedge clk) begin
        if (rst_n) begin
            if (cnt == 3'd3) begin
                data <= d;
                cnt <= 3'd0;
                valid_out <= 1'b1;
            end
            else begin
                cnt <= cnt + 1'b1;
                valid_out <= 1'b0;
                data <= {data[2:0], data[3]};
            end
        end
        else begin
            cnt <= 3'd0;
            valid_out <= 1'b0;
            data <= 4'b0000;
        end
    end
    assign dout = data[3];
endmodule
